package controllers

import java.io.File
import java.nio.charset.StandardCharsets
import java.nio.file.{Files, Path, Paths}

import javax.inject._
import play.api.mvc._

@Singleton
class FileController @Inject()(cc: ControllerComponents) extends AbstractController(cc) {

  private val baseDir: Path = Paths.get("uploads").toAbsolutePath.normalize()

  def getFile(filename: String): Action[AnyContent] = Action {
    val requestedPath = baseDir.resolve(filename).normalize()

    if (!requestedPath.startsWith(baseDir) || Files.isDirectory(requestedPath) || !Files.exists(requestedPath)) {
      NotFound("File not found")
    } else {
      val source = scala.io.Source.fromFile(requestedPath.toFile)(scala.io.Codec.UTF8)
      try {
        Ok(source.mkString).as("text/plain; charset=utf-8")
      } finally {
        source.close()
      }
    }
  }
